// Test suite for precision_builders.hpp
// IO Correctness
TEST(DSEMPrecisionBuilder, HandlesCorrectInput) {
  // Description: Test DSEMPrecisionMatrixBuilder::BuildPrecisionMatrixSparse()
  // with a simple model of two independent states.
  fims_distributions::DSEMPrecisionMatrixBuilder<double> builder;

  // 1. Set up your input parameters
  builder.n_time = 2;
  builder.n_variables = 1;
  const size_t n_k = builder.n_time * builder.n_variables;  // n_k = 2

  // Define a simple RAM model for two independent states with given variances
  fims_distributions::DSEMPrecisionMatrixBuilder<double>::RAMPath var_path1;
  var_path1.type = 2;
  var_path1.from = 1;
  var_path1.to = 1;
  var_path1.beta_index = 1;

  fims_distributions::DSEMPrecisionMatrixBuilder<double>::RAMPath var_path2;
  var_path2.type = 2;
  var_path2.from = 2;
  var_path2.to = 2;
  var_path2.beta_index = 2;

  builder.paths.emplace_back(var_path1);
  builder.paths.emplace_back(var_path2);

  // Strengths of the arrows (standard deviations)
  builder.beta_z.resize(2);
  double sd1 = 0.5;
  double sd2 = 0.4;
  builder.beta_z[0] = sd1;
  builder.beta_z[1] = sd2;

  // 2. Define the expected precision matrix
  // For independent states, Q is diagonal with 1/variance.
  // Q = [[1/sd1^2, 0], [0, 1/sd2^2]]
  Eigen::MatrixXd expected_Q_dense(n_k, n_k);
  expected_Q_dense.setZero();
  expected_Q_dense(0, 0) = 1.0 / (sd1 * sd1);
  expected_Q_dense(1, 1) = 1.0 / (sd2 * sd2);

  // 3. Call the function to be tested
  Eigen::SparseMatrix<double> actual_Q_sparse =
      builder.BuildPrecisionMatrixSparse();
  Eigen::MatrixXd actual_Q_dense = actual_Q_sparse.toDense();

  // 4. Assert that the actual output matches the expected output
  ASSERT_EQ(actual_Q_dense.rows(), n_k);
  ASSERT_EQ(actual_Q_dense.cols(), n_k);
  EXPECT_TRUE(actual_Q_dense.isApprox(expected_Q_dense, 0.0001));
}

TEST(DSEMPrecisionBuilder, HandlesAutoregressivePath) {
  // Description: Test the builder with a simple AR(1)-like model to ensure
  // that causal paths (type=1) are handled correctly.
  fims_distributions::DSEMPrecisionMatrixBuilder<double> builder;

  // 1. Set up a 2-state model: x2 = rho*x1 + eps2; x1 = eps1
  builder.n_time = 2;
  builder.n_variables = 1;
  const size_t n_k = 2;

  double rho = 0.8, sd1 = 1.2, sd2 = 0.5;
  builder.beta_z.resize(3);
  builder.beta_z[0] = rho;
  builder.beta_z[1] = sd1;
  builder.beta_z[2] = sd2;

  // Path 1: Causal link from state 1 to state 2
  fims_distributions::DSEMPrecisionMatrixBuilder<double>::RAMPath ar_path;
  ar_path.type = 1; ar_path.from = 1; ar_path.to = 2; ar_path.beta_index = 1;
  builder.paths.emplace_back(ar_path);

  // Path 2 & 3: Variance for each state's innovation
  fims_distributions::DSEMPrecisionMatrixBuilder<double>::RAMPath var_path1;
  var_path1.type = 2; var_path1.from = 1; var_path1.to = 1; var_path1.beta_index = 2;
  builder.paths.emplace_back(var_path1);

  fims_distributions::DSEMPrecisionMatrixBuilder<double>::RAMPath var_path2;
  var_path2.type = 2; var_path2.from = 2; var_path2.to = 2; var_path2.beta_index = 3;
  builder.paths.emplace_back(var_path2);

  // 2. Define expected precision matrix Q = (I-Rho)^T * V^-1 * (I-Rho)
  // Q = [[1/sd1^2 + rho^2/sd2^2, -rho/sd2^2], [-rho/sd2^2, 1/sd2^2]]
  Eigen::MatrixXd expected_Q(n_k, n_k);
  expected_Q(0, 0) = 1.0 / (sd1 * sd1) + (rho * rho) / (sd2 * sd2);
  expected_Q(0, 1) = -rho / (sd2 * sd2);
  expected_Q(1, 0) = -rho / (sd2 * sd2);
  expected_Q(1, 1) = 1.0 / (sd2 * sd2);

  // 3. Call the function and compare
  Eigen::MatrixXd actual_Q = builder.BuildPrecisionMatrixSparse().toDense();
  EXPECT_TRUE(actual_Q.isApprox(expected_Q, 1e-9));
}

// Edge Handling
TEST(DSEMPrecisionBuilder, HandlesSingleState) {
  // Description: Test with a single state (n_k = 1).
  fims_distributions::DSEMPrecisionMatrixBuilder<double> builder;
  builder.n_time = 1;
  builder.n_variables = 1;

  fims_distributions::DSEMPrecisionMatrixBuilder<double>::RAMPath path;
  path.type = 2;
  path.from = 1;
  path.to = 1;
  path.beta_index = 1;
  builder.paths.emplace_back(path);

  builder.beta_z.resize(1);
  double sd = 2.0;
  builder.beta_z[0] = sd;

  // Expected Q = [[1/sd^2]]
  Eigen::SparseMatrix<double> actual_Q = builder.BuildPrecisionMatrixSparse();

  EXPECT_EQ(actual_Q.rows(), 1);
  EXPECT_EQ(actual_Q.cols(), 1);
  EXPECT_NEAR(actual_Q.coeff(0, 0), 1.0 / (sd * sd), 0.0001);
}

// Error Handling
TEST(DSEMPrecisionBuilder, ThrowsOnZeroDimensions) {
  // Description: Test that builder throws an exception if n_k = 0.
  fims_distributions::DSEMPrecisionMatrixBuilder<double> builder;
  builder.n_time = 0;
  builder.n_variables = 1;
  EXPECT_THROW(builder.BuildPrecisionMatrixSparse(), std::invalid_argument);
}

TEST(DSEMPrecisionBuilder, ThrowsOnOutOfBoundsRAMIndices) {
  // Description: Test that builder throws an exception if RAM path indices
  // are out of bounds.
  fims_distributions::DSEMPrecisionMatrixBuilder<double> builder;
  builder.n_time = 1;
  builder.n_variables = 1;  // n_k = 1
  fims_distributions::DSEMPrecisionMatrixBuilder<double>::RAMPath bad_path;
  bad_path.type = 1;
  bad_path.from = 2;  // Invalid, since n_k is 1 (indices are 1-based)
  bad_path.to = 1;
  bad_path.beta_index = 1;
  builder.paths.emplace_back(bad_path);
  builder.beta_z.resize(1);
  builder.beta_z[0] = 0.5;
  EXPECT_THROW(builder.BuildPrecisionMatrixSparse(), std::invalid_argument);
}

TEST(DSEMPrecisionBuilder, ThrowsOnOutOfBoundsBetaIndex) {
  // Description: Test that builder throws an exception if a beta_index is
  // out of bounds for the beta_z vector.
  fims_distributions::DSEMPrecisionMatrixBuilder<double> builder;
  builder.n_time = 1;
  builder.n_variables = 1;
  builder.paths.clear();
  fims_distributions::DSEMPrecisionMatrixBuilder<double>::RAMPath bad_path;
  bad_path.type = 1;
  bad_path.from = 1;
  bad_path.to = 1;
  bad_path.beta_index = 2;  // Invalid, beta_z only has size 1
  builder.paths.emplace_back(bad_path);
  builder.beta_z.resize(1);
  EXPECT_THROW(builder.BuildPrecisionMatrixSparse(), std::invalid_argument);
}

TEST(DSEMPrecisionBuilder, ThrowsOnSingularCovariance) {
  // Description: Test that the builder fails when the covariance matrix (V)
  // is singular (i.e., not invertible), which occurs if a variable has no
  // variance path.
  fims_distributions::DSEMPrecisionMatrixBuilder<double> builder;
  builder.n_time = 2;
  builder.n_variables = 1; // n_k = 2
  // Only define variance for the first state. The second state has no variance,
  // making the V matrix singular.
  fims_distributions::DSEMPrecisionMatrixBuilder<double>::RAMPath var_path;
  var_path.type = 2; var_path.from = 1; var_path.to = 1; var_path.beta_index = 1;
  builder.paths.emplace_back(var_path);
  builder.beta_z.resize(1);
  builder.beta_z[0] = 1.0;

  // The underlying matrix inversion should fail.
  EXPECT_ANY_THROW(builder.BuildPrecisionMatrixSparse());
}

